import heapq

class Solution(object):
    def minimumCost(self, start, target, specialRoads):
        # Dijkstra on key points: start, target, and endpoints of special roads
        def manhattan(p1, p2):
            return abs(p1[0]-p2[0]) + abs(p1[1]-p2[1])

        # Nodes: start + all special road endpoints + target
        sx, sy = start
        tx, ty = target

        # dist[node] = min cost to reach node
        dist = {}
        dist[(sx, sy)] = 0
        heap = [(0, sx, sy)]

        while heap:
            d, x, y = heapq.heappop(heap)
            if (x, y) in dist and dist[(x, y)] < d:
                continue
            dist[(x, y)] = d

            # Go directly to target
            nd = d + manhattan((x, y), (tx, ty))
            if (tx, ty) not in dist or dist[(tx, ty)] > nd:
                dist[(tx, ty)] = nd
                heapq.heappush(heap, (nd, tx, ty))

            # Use each special road
            for x1, y1, x2, y2, cost in specialRoads:
                # Travel to (x1,y1) then take special road to (x2,y2)
                nd = d + manhattan((x, y), (x1, y1)) + cost
                if (x2, y2) not in dist or dist[(x2, y2)] > nd:
                    dist[(x2, y2)] = nd
                    heapq.heappush(heap, (nd, x2, y2))

        return dist.get((tx, ty), manhattan(start, target))
